import React from 'react';
import { 
  LayoutDashboard, 
  MapPin, 
  DollarSign, 
  Package, 
  Users, 
  Settings,
  LogOut,
  Menu,
  X,
  BarChart3,
  ShieldCheck,
  Sparkles
} from 'lucide-react';
import { User, UserRole } from '../types';

interface LayoutProps {
  children: React.ReactNode;
  activeTab: string;
  setActiveTab: (tab: string) => void;
  userRole: UserRole;
  onLogout?: () => void;
  user?: User;
}

const Layout: React.FC<LayoutProps> = ({ children, activeTab, setActiveTab, userRole, onLogout, user }) => {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = React.useState(false);

  const menuItems = [
    { id: 'dashboard', label: 'Painel Inicial', icon: LayoutDashboard, permission: true },
    { id: 'production', label: 'Produção', icon: MapPin, permission: user?.permissions.production },
    { id: 'finance', label: 'Financeiro', icon: DollarSign, permission: user?.permissions.finance },
    { id: 'inventory', label: 'Almoxarifado', icon: Package, permission: user?.permissions.inventory },
    { id: 'employees', label: 'Equipe & RH', icon: Users, permission: user?.permissions.employees },
    { id: 'analytics', label: 'Relatórios', icon: BarChart3, permission: user?.permissions.analytics },
    { id: 'ai', label: 'Assistente Fera Bot', icon: Sparkles, permission: user?.permissions.ai },
    { id: 'management', label: 'Gestão de Acessos', icon: ShieldCheck, permission: userRole === UserRole.MASTER || userRole === UserRole.ADMIN },
    { id: 'settings', label: 'Configurações', icon: Settings, permission: userRole === UserRole.MASTER || userRole === UserRole.ADMIN },
  ];

  const visibleItems = menuItems.filter(item => item.permission);

  const translateTab = (id: string) => {
    const item = menuItems.find(m => m.id === id);
    return item ? item.label : id;
  };

  const roleLabel = (role: UserRole) => {
    switch(role) {
      case UserRole.MASTER: return 'DIRETORIA MASTER';
      case UserRole.ADMIN: return 'GERÊNCIA';
      case UserRole.OPERATIONAL: return 'OPERACIONAL';
      default: return role;
    }
  };

  const Sidebar = () => (
    <div className="flex flex-col h-full bg-[#010a1b] text-slate-400 w-64 fixed left-0 top-0 z-50 border-r border-white/5">
      <div className="p-8 border-b border-white/5">
        <h1 className="text-xl font-black text-white uppercase tracking-tighter leading-none">
          FERA SERVICE
        </h1>
      </div>

      <div className="p-6 border-b border-white/5 bg-[#010a1b]">
        <div className="px-2">
          <p className="text-[11px] font-black text-white truncate uppercase tracking-tight">{user?.name}</p>
          <p className="text-[9px] text-slate-500 font-black uppercase tracking-widest mt-0.5">{roleLabel(userRole)}</p>
        </div>
      </div>

      <nav className="flex-1 px-3 py-8 space-y-2 overflow-y-auto">
        {visibleItems.map((item) => (
          <button
            key={item.id}
            onClick={() => {
              setActiveTab(item.id);
              setIsMobileMenuOpen(false);
            }}
            className={`w-full flex items-center gap-4 px-4 py-4 rounded-2xl transition-all text-[10px] font-black uppercase tracking-widest ${
              activeTab === item.id 
                ? 'bg-emerald-600 text-white shadow-lg' 
                : 'hover:bg-white/5 hover:text-white'
            }`}
          >
            <item.icon size={18} />
            {item.label}
          </button>
        ))}
      </nav>

      <div className="p-6 border-t border-white/5">
        <button 
          onClick={onLogout}
          className="flex items-center gap-4 px-4 py-3 w-full text-slate-500 hover:text-rose-400 hover:bg-rose-400/5 rounded-2xl transition-all text-[10px] font-black uppercase tracking-widest"
        >
          <LogOut size={18} />
          Encerrar Sessão
        </button>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans antialiased">
      <div className="lg:hidden flex items-center justify-between px-6 py-4 bg-white border-b-4 border-[#010a1b] sticky top-0 z-40">
        <div className="flex items-center">
           <span className="font-black text-[#010a1b] text-sm uppercase tracking-tighter">
             {translateTab(activeTab)}
           </span>
        </div>
        <button 
          onClick={() => setIsMobileMenuOpen(true)}
          className="p-2.5 text-[#010a1b] hover:bg-slate-100 rounded-xl transition-all active:scale-90"
        >
          <Menu size={22} />
        </button>
      </div>

      <div className="hidden lg:block">
        <Sidebar />
      </div>

      {isMobileMenuOpen && (
        <div className="lg:hidden fixed inset-0 z-[100]">
          <div className="absolute inset-0 bg-[#010a1b]/80 backdrop-blur-sm" onClick={() => setIsMobileMenuOpen(false)} />
          <div className="absolute left-0 top-0 h-full w-64 shadow-2xl animate-in slide-in-from-left duration-200">
            <Sidebar />
          </div>
        </div>
      )}

      <main className="flex-1 lg:ml-64 p-6 lg:p-12">
        <div className="max-w-7xl mx-auto">
          {children}
        </div>
      </main>
    </div>
  );
};

export default Layout;

import { useState, useEffect, useCallback, useRef } from 'react';
import { AppState, UserRole } from './types';
import { INITIAL_STATE } from './constants';
import { supabase, fetchUserProfile, fetchCompleteCompanyData, signOut } from './lib/supabase';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import Production from './components/Production';
import Finance from './components/Finance';
import Inventory from './components/Inventory';
import Employees from './components/Employees';
import Settings from './components/Settings';
import Login from './components/Login';
import Analytics from './components/Analytics';
import Management from './components/Management';
import AIAssistant from './components/AIAssistant';
import ConfirmationModal from './components/ConfirmationModal';
import { RefreshCw, LogOut, AlertCircle, X, CheckCircle2 } from 'lucide-react';

const App = () => {
  const [isInitializing, setIsInitializing] = useState(true);
  const [state, setState] = useState<AppState>(INITIAL_STATE);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [showLogoutConfirm, setShowLogoutConfirm] = useState(false);
  const [notification, setNotification] = useState<{message: string, type: 'success' | 'error'} | null>(null);
  const [initError, setInitError] = useState<string | null>(null);

  // Ref para rastrear o ID do usuário atual e evitar sincronizações duplicadas
  const currentUserRef = useRef<string | null>(null);

  const notify = (message: string, type: 'success' | 'error' = 'success') => {
    setNotification({ message, type });
    setTimeout(() => setNotification(null), 3000);
  };

  const syncData = useCallback(async (userId: string, retryCount = 0) => {
    try {
      console.log(`Sincronizando: ${userId} (Tentativa ${retryCount})`);
      const profile = await fetchUserProfile(userId);

      if (!profile) {
        if (retryCount < 2) { 
          setTimeout(() => syncData(userId, retryCount + 1), 1500);
          return;
        }
        setInitError("PERFIL OPERACIONAL NÃO ENCONTRADO. Se você deletou sua conta, clique em 'SAIR E RECOMEÇAR' para criar uma nova credencial Master.");
        setIsInitializing(false);
        return;
      }

      if (!profile.company_id) {
        setInitError("USUÁRIO SEM UNIDADE. Sua conta existe mas não está vinculada a nenhuma empresa operativa.");
        setIsInitializing(false);
        return;
      }

      const companyData = await fetchCompleteCompanyData(profile.company_id);

      setState(prev => ({
        ...prev,
        currentUser: {
          id: profile.id,
          email: profile.email || '',
          name: profile.full_name || 'Usuário',
          role: profile.role as UserRole || UserRole.OPERATIONAL,
          companyId: profile.company_id,
          status: profile.status as 'ativo' | 'suspenso' || 'ativo',
          permissions: profile.permissions || INITIAL_STATE.users[0].permissions
        },
        ...(companyData || {})
      }));

      currentUserRef.current = userId;
      setInitError(null);
      setIsInitializing(false);
    } catch (e: any) {
      console.error("Erro crítico na sincronização:", e);
      setInitError("FALHA DE COMUNICAÇÃO. Verifique sua conexão ou tente novamente em instantes.");
      setIsInitializing(false);
    }
  }, []);

  useEffect(() => {
    const initAuth = async () => {
      try {
        const { data: { session } } = await supabase.auth.getSession();
        if (session?.user) {
          currentUserRef.current = session.user.id;
          await syncData(session.user.id);
        } else {
          setIsInitializing(false);
        }
      } catch (e) {
        setInitError("ERRO DE AUTENTICAÇÃO.");
        setIsInitializing(false);
      }
    };

    initAuth();

    const { data: { subscription } } = supabase.auth.onAuthStateChange((event, session) => {
      if (event === 'SIGNED_IN' && session?.user) {
        // Só reinicializa se o usuário mudou ou se não temos um usuário atual
        if (currentUserRef.current !== session.user.id) {
          setIsInitializing(true);
          setInitError(null);
          syncData(session.user.id);
        }
      } else if (event === 'SIGNED_OUT') {
        currentUserRef.current = null;
        setState({ ...INITIAL_STATE, currentUser: null });
        setIsInitializing(false);
        setInitError(null);
      }
    });

    return () => subscription.unsubscribe();
  }, [syncData]);

  if (isInitializing) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-[#020617] text-center p-6">
        <div className="relative">
          <div className="w-16 h-16 border-4 border-slate-800 border-t-emerald-500 rounded-full animate-spin shadow-[0_0_20px_rgba(16,185,129,0.2)]" />
          <div className="absolute inset-0 flex items-center justify-center">
             <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse shadow-[0_0_10px_rgba(16,185,129,0.8)]" />
          </div>
        </div>
        <div className="mt-8 space-y-2">
          <h2 className="font-black text-white uppercase tracking-[0.4em] text-[11px] opacity-90">Fera Service Cloud</h2>
          <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest animate-pulse">Sincronizando Banco de Dados...</p>
        </div>
      </div>
    );
  }

  if (initError) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-[#020617] p-6">
        <div className="bg-slate-900 border border-white/10 p-10 rounded-[40px] max-w-sm w-full animate-in zoom-in-95 backdrop-blur-xl text-center shadow-2xl">
           <div className="w-16 h-16 bg-rose-500/10 rounded-[24px] flex items-center justify-center mx-auto mb-6">
              <AlertCircle size={32} className="text-rose-500" />
           </div>
           <h2 className="font-black text-white uppercase tracking-widest text-[11px] mb-4">Acesso Bloqueado</h2>
           <p className="text-[11px] text-slate-400 font-bold leading-relaxed mb-10 uppercase tracking-tight">{initError}</p>

           <div className="space-y-3">
              <button onClick={() => window.location.reload()} className="w-full bg-white text-slate-900 py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-emerald-500 hover:text-white transition-all shadow-xl active:scale-95 flex items-center justify-center gap-2">
                  <RefreshCw size={16} /> Tentar Reconectar
              </button>
              <button onClick={async () => await signOut()} className="w-full bg-rose-600 text-white py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-rose-500 transition-all flex items-center justify-center gap-2 shadow-lg shadow-rose-900/20">
                  <LogOut size={16} /> Sair e Recomeçar
              </button>
           </div>
        </div>
      </div>
    );
  }

  if (!state.currentUser) return <Login onLogin={() => {}} users={[]} />;

  return (
    <>
      <Layout activeTab={activeTab} setActiveTab={setActiveTab} userRole={state.currentUser.role} user={state.currentUser} onLogout={() => setShowLogoutConfirm(true)}>
        {(() => {
          const props = { state, setState, setActiveTab, notify };
          switch (activeTab) {
            case 'dashboard': return <Dashboard {...props} />;
            case 'production': return <Production {...props} />;
            case 'finance': return <Finance {...props} />;
            case 'inventory': return <Inventory {...props} />;
            case 'employees': return <Employees {...props} />;
            case 'analytics': return <Analytics {...props} />;
            case 'ai': return <AIAssistant state={state} />;
            case 'management': return <Management {...props} />;
            case 'settings': return <Settings {...props} />;
            default: return <Dashboard {...props} />;
          }
        })()}
      </Layout>

      {notification && (
        <div className={`fixed bottom-8 left-1/2 -translate-x-1/2 z-[1000] px-6 py-4 rounded-2xl shadow-2xl flex items-center gap-4 animate-in slide-in-from-bottom-4 duration-300 border ${notification.type === 'success' ? 'bg-emerald-600 border-emerald-500 text-white' : 'bg-rose-600 border-rose-500 text-white'}`}>
           {notification.type === 'success' ? <CheckCircle2 size={18}/> : <AlertCircle size={18}/>}
           <p className="text-[10px] font-black uppercase tracking-widest">{notification.message}</p>
           <button onClick={() => setNotification(null)} className="ml-2 hover:opacity-70"><X size={14}/></button>
        </div>
      )}

      <ConfirmationModal isOpen={showLogoutConfirm} onClose={() => setShowLogoutConfirm(false)} onConfirm={async () => { await signOut(); setShowLogoutConfirm(false); }} title="Sair do Sistema" message="Deseja encerrar sua sessão segura?" confirmText="Sair" type="warning" />
    </>
  );
};

export default App;

import { GoogleGenAI } from "@google/genai";
import { AppState } from "../types";

export const askAssistant = async (history: { role: 'user' | 'bot'; text: string }[], state: AppState) => {
  // Inicialização usando a API KEY do ambiente conforme as diretrizes
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Obter meta do mês atual para o contexto (Formato YYYY-MM)
  const currentMonthKey = `${new Date().getFullYear()}-${String(new Date().getMonth() + 1).padStart(2, '0')}`;
  const currentGoal = state.monthlyGoals[currentMonthKey] || { production: 0, revenue: 0 };

  // Compilação do contexto operacional para a IA "enxergar" o sistema
  const context = {
    totalAreas: state.areas.length,
    productionM2: state.areas.reduce((acc, area) => acc + area.services.reduce((sAcc, s) => sAcc + s.areaM2, 0), 0),
    totalRevenue: state.areas.reduce((acc, area) => acc + area.services.reduce((sAcc, s) => sAcc + s.totalValue, 0), 0),
    cashBalance: state.cashIn.reduce((acc, c) => acc + c.value, 0) - state.cashOut.reduce((acc, c) => acc + c.value, 0),
    lowStockItems: state.inventory.filter(i => i.currentQty <= i.minQty).map(i => i.name),
    goalM2: currentGoal.production,
    activeEmployees: state.employees.filter(e => e.status === 'active').length
  };

  const contents = history.map(msg => ({
    role: msg.role === 'bot' ? 'model' : 'user',
    parts: [{ text: msg.text }]
  }));

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: contents,
      config: {
        systemInstruction: `Você é o Diretor de Operações da Fera Service. 
        Você tem acesso aos seguintes dados em tempo real: ${JSON.stringify(context)}.
        Sua missão é ajudar o gestor a tomar decisões sobre faturamento, produtividade e estoque.
        Utilize a ferramenta de busca do Google para obter regulamentações urbanas, preços de mercado de insumos ou notícias do setor se necessário.
        Seja conciso, profissional e use R$ para valores monetários.`,
        temperature: 0.7,
        tools: [{ googleSearch: {} }],
        thinkingConfig: { thinkingBudget: 4000 }
      }
    });

    // Acessa a propriedade .text diretamente da resposta
    return response.text;
  } catch (error) {
    console.error("Erro no Fera Bot:", error);
    return "Desculpe, tive um problema ao processar sua solicitação. Verifique sua conexão ou tente novamente.";
  }
};

