import React, { useState, useMemo } from 'react';
import { AppState, ServiceType } from '../types';
import { SERVICE_OPTIONS } from '../constants';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer,
  Cell,
  Legend
} from 'recharts';
import { 
  TrendingUp, 
  AlertTriangle, 
  Wallet, 
  Map, 
  Calendar, 
  Filter, 
  X, 
  Package,
  Layers,
  Target,
  Activity,
  UserCheck,
  ArrowUpRight
} from 'lucide-react';

interface DashboardProps {
  state: AppState;
  setState: React.Dispatch<React.SetStateAction<AppState>>;
  setActiveTab: (tab: string) => void;
}

type MetricType = 'production' | 'revenue' | 'balance';

const Dashboard: React.FC<DashboardProps> = ({ state, setActiveTab }) => {
  const [activeMetric, setActiveMetric] = useState<MetricType>('production');
  const [selectedService, setSelectedService] = useState<string>('TOTAL');
  const [showFilter, setShowFilter] = useState(false);

  const [rangeMonths, setRangeMonths] = useState(6);
  const [endPeriod, setEndPeriod] = useState(() => {
    const now = new Date();
    return `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`;
  });

  const COLORS = {
    realized: '#010a1b',
    goal: '#10b981',
    goalOpacity: 'rgba(16, 185, 129, 0.2)',
    danger: '#ef4444'
  };

  const currentUnit = useMemo(() => {
    if (selectedService === 'TOTAL') return 'm²';
    return selectedService.includes('KM') ? 'KM' : 'm²';
  }, [selectedService]);

  const displayTitle = useMemo(() => {
    if (selectedService === 'TOTAL') return 'PRODUÇÃO GERAL ACUMULADA (m²)';
    const hasUnit = selectedService.includes('(m²)') || selectedService.includes('(KM)') || selectedService.includes('m²') || selectedService.includes('KM');
    return `PRODUÇÃO REALIZADA: ${selectedService}${hasUnit ? '' : ` (${currentUnit})`}`;
  }, [selectedService, currentUnit]);

  const formatNumber = (v: number) => v.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
  const formatMoney = (v: number) => v.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL', minimumFractionDigits: 2, maximumFractionDigits: 2 });

  const monthlySeries = useMemo(() => {
    const months = [];
    const [year, month] = endPeriod.split('-').map(Number);

    for (let i = rangeMonths - 1; i >= 0; i--) {
      const d = new Date(year, month - 1 - i, 1);
      const yKey = d.getFullYear();
      const mKey = String(d.getMonth() + 1).padStart(2, '0');

      months.push({
        label: d.toLocaleString('pt-BR', { month: 'short' }).toUpperCase(),
        fullName: d.toLocaleString('pt-BR', { month: 'long', year: 'numeric' }).toUpperCase(),
        key: `${yKey}-${mKey}` 
      });
    }
    return months;
  }, [endPeriod, rangeMonths]);

  const chartData = useMemo(() => {
    return monthlySeries.map(m => {
      let prod = 0;
      let rev = 0;

      state.areas.forEach(area => {
        const finishedInThisMonth = area.status === 'finished' && area.endDate?.startsWith(m.key);

        if (finishedInThisMonth) {
          (area.services || []).forEach(s => {
            if (selectedService === 'TOTAL' || s.type === selectedService) {
              prod += s.areaM2;
              rev += s.totalValue;
            }
          });
        }
      });

      const inc = state.cashIn.filter(c => c.date?.startsWith(m.key)).reduce((acc, c) => acc + c.value, 0);
      const out = state.cashOut.filter(c => c.date?.startsWith(m.key)).reduce((acc, c) => acc + c.value, 0);

      const monthlyGoal = state.monthlyGoals[m.key] || { production: 0, revenue: 0 };
      const productionGoal = selectedService === 'TOTAL' 
        ? monthlyGoal.production 
        : (state.serviceGoals[selectedService as ServiceType] || 0);

      return {
        name: m.label,
        fullName: m.fullName,
        production: prod,
        productionGoal: productionGoal,
        revenue: rev,
        revenueGoal: monthlyGoal.revenue,
        balance: inc - out,
        income: inc,
        expense: out
      };
    });
  }, [state.areas, state.cashIn, state.cashOut, monthlySeries, state.monthlyGoals, state.serviceGoals, selectedService]);

  // Ranking de Produtividade por Responsável
  const responsibleRanking = useMemo(() => {
    const rankingMap: Record<string, { id: string, name: string, production: number, revenue: number }> = {};

    state.areas.forEach(area => {
      // Consideramos apenas O.S. finalizadas no mês de referência atual (endPeriod)
      const isFinishedInPeriod = area.status === 'finished' && area.endDate?.startsWith(endPeriod);

      if (isFinishedInPeriod) {
        const respId = area.responsibleEmployeeId || 'unassigned';
        const respName = respId === 'unassigned' 
          ? 'SEM RESPONSÁVEL' 
          : (state.employees.find(e => e.id === respId)?.name || 'EX-COLABORADOR');

        if (!rankingMap[respId]) {
          rankingMap[respId] = { id: respId, name: respName, production: 0, revenue: 0 };
        }

        (area.services || []).forEach(s => {
          if (selectedService === 'TOTAL' || s.type === selectedService) {
            rankingMap[respId].production += Number(s.areaM2) || 0;
            rankingMap[respId].revenue += Number(s.totalValue) || 0;
          }
        });
      }
    });

    return Object.values(rankingMap).sort((a, b) => b.revenue - a.revenue);
  }, [state.areas, state.employees, endPeriod, selectedService]);

  const periodTotals = useMemo(() => {
    const filterKey = endPeriod; 
    const currentMonthGoal = state.monthlyGoals[filterKey] || { production: 0, revenue: 0 };

    let prodMonth = 0;
    let revMonth = 0;

    state.areas.forEach(area => {
      const isFinishedInPeriod = area.status === 'finished' && area.endDate?.startsWith(filterKey);

      if (isFinishedInPeriod) {
        (area.services || []).forEach(s => {
          if (selectedService === 'TOTAL' || s.type === selectedService) {
            prodMonth += s.areaM2;
            revMonth += s.totalValue;
          }
        });
      }
    });

    const activeDays = new Set();
    state.attendanceRecords.forEach(record => {
      if (record.date.startsWith(filterKey) && (record.status === 'present' || record.status === 'partial')) {
        activeDays.add(record.date);
      }
    });

    const workedDaysCount = activeDays.size || 0;
    const avgDailyProduction = workedDaysCount > 0 ? prodMonth / workedDaysCount : 0;

    const goalProd = selectedService === 'TOTAL' 
      ? currentMonthGoal.production 
      : (state.serviceGoals[selectedService as ServiceType] || 0);

    return {
      production: prodMonth,
      revenue: revMonth,
      avgDailyProduction,
      workedDaysCount,
      balance: state.cashIn.filter(c => c.date?.startsWith(filterKey)).reduce((acc, c) => acc + c.value, 0) - state.cashOut.filter(c => c.date?.startsWith(filterKey)).reduce((acc, c) => acc + c.value, 0),
      inventoryValue: state.inventory.reduce((acc, item) => acc + ((item.currentQty || 0) * (item.unitValue || 0)), 0),
      goalProd: goalProd,
      goalRev: currentMonthGoal.revenue,
      prodPercentage: goalProd > 0 ? (prodMonth / goalProd) * 100 : 0,
      revPercentage: currentMonthGoal.revenue > 0 ? (revMonth / currentMonthGoal.revenue) * 100 : 0
    };
  }, [state.areas, state.cashIn, state.cashOut, state.attendanceRecords, state.monthlyGoals, state.serviceGoals, state.inventory, endPeriod, selectedService]);

  const stats = [
    { 
      id: 'production', 
      label: selectedService === 'TOTAL' ? `PRODUÇÃO MENSAL (${currentUnit})` : `PRODUÇÃO: ${selectedService.split(' (')[0]}`, 
      value: `${formatNumber(periodTotals.production)} ${currentUnit}`, 
      progress: periodTotals.prodPercentage, 
      icon: Map, 
      color: 'text-blue-600', 
      bg: 'bg-blue-50' 
    },
    { 
      id: 'daily_avg', 
      label: 'MÉDIA PROD. DIÁRIA', 
      value: `${formatNumber(periodTotals.avgDailyProduction)} ${currentUnit}`, 
      subValue: `Base: ${periodTotals.workedDaysCount} dias úteis`,
      icon: Activity, 
      color: 'text-indigo-600', 
      bg: 'bg-indigo-50' 
    },
    { id: 'revenue', label: 'FATURAMENTO MÊS', value: formatMoney(periodTotals.revenue), progress: periodTotals.revPercentage, icon: TrendingUp, color: 'text-emerald-600', bg: 'bg-emerald-50' },
    { id: 'stock', label: 'ESTOQUE CRÍTICO', value: `${state.inventory.filter(i => i.currentQty <= i.minQty).length} itens`, icon: AlertTriangle, color: 'text-rose-600', bg: 'bg-rose-50' },
  ];

  return (
    <div className="space-y-6 pb-20">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-xl font-black text-[#010a1b] tracking-tight uppercase">Monitoramento Estratégico</h2>
          <p className="text-[10px] text-[#2e3545] font-bold uppercase tracking-widest opacity-70">Cálculo baseado em O.S. Finalizadas e Frequência</p>
        </div>

        <div className="flex flex-col sm:flex-row items-center gap-3 w-full md:w-auto">
          <div className="relative w-full sm:w-64">
             <div className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400">
                <Layers size={14} />
             </div>
             <select 
              className="w-full bg-white border border-slate-200 pl-10 pr-4 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest outline-none focus:border-[#010a1b] shadow-sm appearance-none cursor-pointer"
              value={selectedService}
              onChange={(e) => setSelectedService(e.target.value)}
             >
                <option value="TOTAL">Produção Geral (m²)</option>
                {SERVICE_OPTIONS.map(opt => (
                  <option key={opt} value={opt}>{opt}</option>
                ))}
             </select>
          </div>

          <div className="relative w-full sm:w-auto">
            <button 
              onClick={() => setShowFilter(!showFilter)}
              className="w-full flex items-center justify-between md:justify-start gap-3 bg-white border border-slate-200 px-4 py-2.5 rounded-xl shadow-sm hover:border-[#010a1b] transition-all group"
            >
              <div className="flex items-center gap-2">
                <Calendar size={16} className="text-[#2e3545] group-hover:text-[#010a1b]" />
                <span className="text-[10px] font-black text-[#2e3545] uppercase tracking-widest whitespace-nowrap">
                  MÊS: {monthlySeries[monthlySeries.length-1].fullName}
                </span>
              </div>
              <Filter size={14} className="text-slate-300" />
            </button>

            {showFilter && (
              <div className="absolute right-0 top-full mt-2 w-full md:w-72 bg-white border border-slate-200 rounded-2xl shadow-2xl z-[100] p-6 animate-in fade-in slide-in-from-top-2 duration-200">
                <div className="flex justify-between items-center mb-4">
                  <h4 className="text-[10px] font-black text-[#010a1b] uppercase tracking-[0.2em]">Configurar Período</h4>
                  <button onClick={() => setShowFilter(false)} className="text-slate-300 hover:text-[#010a1b]"><X size={16} /></button>
                </div>
                <div className="space-y-4">
                  <div className="space-y-1">
                    <label className="text-[9px] font-black text-[#2e3545] uppercase tracking-widest">Mês Referência</label>
                    <input type="month" className="w-full bg-slate-50 border border-slate-200 p-3 rounded-xl text-xs font-bold outline-none focus:border-[#010a1b]" value={endPeriod} onChange={(e) => setEndPeriod(e.target.value)} />
                  </div>
                  <div className="space-y-1">
                    <label className="text-[9px] font-black text-[#2e3545] uppercase tracking-widest">Janela do Gráfico</label>
                    <select className="w-full bg-slate-50 border border-slate-200 p-3 rounded-xl text-xs font-bold outline-none focus:border-[#010a1b]" value={rangeMonths} onChange={(e) => setRangeMonths(Number(e.target.value))}>
                      <option value={3}>3 Meses</option>
                      <option value={6}>6 Meses</option>
                      <option value={12}>12 Meses</option>
                    </select>
                  </div>
                  <button onClick={() => setShowFilter(false)} className="w-full bg-[#010a1b] text-white py-3.5 rounded-xl text-[9px] font-black uppercase tracking-widest">Aplicar Filtros</button>
                </div>
              </div>
            )}
          </div>
        </div>
      </header>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
        {stats.map((stat) => (
          <button 
            key={stat.id} 
            onClick={() => {
              if (stat.id === 'stock') setActiveTab('inventory');
              else if (stat.id === 'revenue') setActiveMetric('revenue');
              else setActiveMetric('production');
            }}
            className={`bg-white p-6 border text-left transition-all relative overflow-hidden group rounded-[32px] ${activeMetric === stat.id ? 'border-[#010a1b] ring-4 ring-[#010a1b]/5 shadow-lg' : 'border-slate-200 hover:border-[#010a1b]'}`}
          >
            <div className="flex justify-between items-start mb-4">
              <span className={`p-2.5 rounded-xl ${stat.bg} ${stat.color}`}><stat.icon size={20} /></span>
              {stat.progress !== undefined && (
                <span className={`text-[10px] font-black ${stat.progress >= 100 ? 'text-emerald-600' : 'text-[#2e3545]'}`}>
                   {stat.progress.toFixed(0)}%
                </span>
              )}
            </div>
            <p className="text-[9px] font-black text-[#2e3545] uppercase tracking-widest mb-1 truncate">{stat.label}</p>
            <p className="text-xl font-black text-[#010a1b] truncate">{stat.value}</p>
            {(stat as any).subValue && (
              <p className="text-[8px] font-bold text-slate-400 uppercase mt-1">{(stat as any).subValue}</p>
            )}
            {stat.progress !== undefined && (
              <div className="mt-4 w-full h-1.5 bg-slate-100 rounded-full overflow-hidden">
                <div className={`h-full transition-all duration-1000 ${stat.progress >= 100 ? 'bg-emerald-500' : 'bg-blue-500'}`} style={{ width: `${Math.min(stat.progress, 100)}%` }} />
              </div>
            )}
          </button>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 space-y-6">
          <div className="bg-white border border-slate-200 rounded-[32px] p-8 shadow-sm min-h-[400px] w-full">
            <h3 className="font-black text-[10px] text-[#2e3545] uppercase tracking-[0.2em] mb-8">
              {displayTitle}
            </h3>
            <div className="h-80 w-full">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={chartData}>
                  <CartesianGrid strokeDasharray="2 2" vertical={false} stroke="#f1f5f9" />
                  <XAxis dataKey="name" fontSize={10} fontWeights="900" stroke="#94a3b8" axisLine={false} tickLine={false} />
                  <YAxis 
                    fontSize={10} 
                    fontWeight="900" 
                    stroke="#94a3b8" 
                    axisLine={false} 
                    tickLine={false} 
                    tickFormatter={(value) => value.toLocaleString('pt-BR')}
                  />
                  <Tooltip 
                    cursor={{fill: '#f8fafc'}} 
                    formatter={(value: number) => [formatNumber(value), ""]}
                    contentStyle={{ border: 'none', borderRadius: '16px', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)', fontSize: '11px', fontWeight: '900', color: '#010a1b', textTransform: 'uppercase' }}
                  />
                  <Legend verticalAlign="top" align="right" iconType="circle" wrapperStyle={{ paddingBottom: '20px', fontSize: '10px', fontWeight: '900', textTransform: 'uppercase' }} />

                  <Bar 
                    name="Realizado" 
                    dataKey={activeMetric} 
                    fill={COLORS.realized}
                    radius={[4, 4, 0, 0]} 
                    barSize={20}
                  >
                    {chartData.map((entry, index) => {
                      let color = COLORS.realized;
                      if(activeMetric === 'balance') color = entry.balance >= 0 ? COLORS.goal : COLORS.danger;
                      return <Cell key={`cell-${index}`} fill={color} />;
                    })}
                  </Bar>

                  {(activeMetric === 'production' || activeMetric === 'revenue') && (
                    <Bar 
                      name="Meta" 
                      dataKey={activeMetric === 'production' ? 'productionGoal' : 'revenueGoal'} 
                      fill={COLORS.goal} 
                      fillOpacity={0.4} 
                      radius={[4, 4, 0, 0]} 
                      barSize={20} 
                    />
                  )}
                </BarChart>
              </ResponsiveContainer>
            </div>
          </div>

          {/* NOVO: Produtividade por Responsável (Substituto das Equipes) */}
          <div className="bg-white border border-slate-200 rounded-[32px] p-8 shadow-sm">
             <div className="flex items-center justify-between mb-8">
               <div>
                  <h3 className="font-black text-[10px] text-[#2e3545] uppercase tracking-[0.2em] flex items-center gap-2">
                    <UserCheck size={16} className="text-emerald-500" /> Desempenho por Colaborador Responsável
                  </h3>
                  <p className="text-[8px] font-bold text-slate-400 uppercase tracking-widest mt-1">Somas baseadas em O.S. finalizadas no período</p>
               </div>
               <span className="text-[9px] font-black text-slate-500 uppercase bg-slate-100 px-3 py-1 rounded-lg">Mês: {monthlySeries[monthlySeries.length-1].label}</span>
             </div>

             <div className="space-y-6">
                {responsibleRanking.length === 0 ? (
                  <div className="py-12 text-center">
                    <p className="text-[10px] font-black text-slate-300 uppercase italic">Nenhuma produção vinculada e finalizada neste mês</p>
                  </div>
                ) : (
                  responsibleRanking.map((resp, idx) => {
                    const maxRevenue = Math.max(...responsibleRanking.map(r => r.revenue));
                    const percentage = maxRevenue > 0 ? (resp.revenue / maxRevenue) * 100 : 0;

                    return (
                      <div key={resp.id} className="group">
                        <div className="flex justify-between items-end mb-2">
                           <div className="flex items-center gap-3">
                              <div className="w-8 h-8 rounded-lg bg-slate-900 text-white flex items-center justify-center text-[10px] font-black shadow-lg">
                                {idx + 1}
                              </div>
                              <div>
                                 <p className="text-[11px] font-black text-slate-900 uppercase tracking-tight">{resp.name}</p>
                                 <p className="text-[8px] font-bold text-slate-400 uppercase tracking-widest">Responsável Técnico</p>
                              </div>
                           </div>
                           <div className="text-right">
                              <p className="text-[11px] font-black text-emerald-600">{formatMoney(resp.revenue)}</p>
                              <p className="text-[9px] font-black text-slate-500">{formatNumber(resp.production)} {currentUnit}</p>
                           </div>
                        </div>
                        <div className="w-full h-1.5 bg-slate-100 rounded-full overflow-hidden">
                           <div 
                            className={`h-full transition-all duration-1000 ${resp.id === 'unassigned' ? 'bg-slate-400' : 'bg-emerald-500'}`} 
                            style={{ width: `${percentage}%` }} 
                           />
                        </div>
                      </div>
                    );
                  })
                )}
             </div>
          </div>
        </div>

        <div className="bg-[#010a1b] text-white rounded-[40px] p-10 shadow-xl space-y-10 flex flex-col border border-white/5">
          <div className="flex items-center gap-3">
            <TrendingUp size={24} className="text-emerald-400" />
            <h3 className="font-black text-xs uppercase tracking-[0.2em]">Desempenho da Produção</h3>
          </div>

          <div className="space-y-8 flex-1">
            <div className="space-y-3">
              <div className="flex justify-between">
                <p className="text-[10px] font-black text-slate-500 uppercase">Produção Realizada</p>
                <p className="text-[10px] font-black">{periodTotals.prodPercentage.toFixed(1)}%</p>
              </div>
              <div className="w-full h-2.5 bg-white/10 rounded-full overflow-hidden">
                <div className="h-full bg-blue-500 transition-all duration-700 shadow-[0_0_10px_rgba(59,130,246,0.5)]" style={{ width: `${Math.min(periodTotals.prodPercentage, 100)}%` }} />
              </div>
              <p className="text-[8px] font-black text-slate-400 text-right uppercase">Realizado: {formatNumber(periodTotals.production)} {currentUnit} / Meta: {formatNumber(periodTotals.goalProd)} {currentUnit}</p>
            </div>

            <div className="space-y-3">
              <div className="flex justify-between">
                <p className="text-[10px] font-black text-slate-500 uppercase">Faturamento Auditado</p>
                <p className="text-[10px] font-black">{periodTotals.revPercentage.toFixed(1)}%</p>
              </div>
              <div className="w-full h-2.5 bg-white/10 rounded-full overflow-hidden">
                <div className="h-full bg-emerald-500 transition-all duration-700 shadow-[0_0_10px_rgba(16,185,129,0.5)]" style={{ width: `${Math.min(periodTotals.revPercentage, 100)}%` }} />
              </div>
              <p className="text-[8px] font-black text-slate-400 text-right uppercase">Meta: {formatMoney(periodTotals.goalRev)}</p>
            </div>

            <div className="pt-8 border-t border-white/10">
               <p className="text-[9px] font-black text-slate-500 uppercase mb-2 tracking-widest">Valor Imobilizado (Estoque)</p>
               <p className="text-2xl font-black text-white tracking-tighter">{formatMoney(state.inventory.reduce((acc, item) => acc + ((item.currentQty || 0) * (item.unitValue || 0)), 0))}</p>
            </div>
          </div>

          <button 
            onClick={() => setActiveTab('production')}
            className="w-full py-5 bg-white text-[#010a1b] rounded-2xl font-black text-[10px] uppercase shadow-2xl hover:bg-emerald-400 hover:text-white transition-all active:scale-95"
          >
             Acessar Gestão de Produção
          </button>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { AppState } from '../types';
import { Plus, ArrowDownCircle, ArrowUpCircle, X, Wallet, Trash2, Edit2, Loader2, DollarSign, Calendar, Tag, Search, Filter, CheckSquare, Square, ChevronDown } from 'lucide-react';
import ConfirmationModal from './ConfirmationModal';
import { dbSave, dbDelete, fetchCompleteCompanyData } from '../lib/supabase';

interface FinanceProps {
  state: AppState;
  setState: React.Dispatch<React.SetStateAction<AppState>>;
  notify: (msg: string, type?: 'success' | 'error') => void;
}

const Finance: React.FC<FinanceProps> = ({ state, setState, notify }) => {
  const [activeTab, setActiveTab] = useState<'in' | 'out'>('in');
  const [showForm, setShowForm] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [confirmDelete, setConfirmDelete] = useState<{ isOpen: boolean; id: string } | null>(null);

  // Estados para Filtros
  const [searchQuery, setSearchQuery] = useState('');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [categoryFilter, setCategoryFilter] = useState<string[]>([]);
  const [isCategoryDropdownOpen, setIsCategoryDropdownOpen] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);

  const [formData, setFormData] = useState({
    type: 'in' as 'in' | 'out',
    value: '',
    date: new Date().toISOString().split('T')[0],
    reference: '',
    category: 'Geral'
  });

  // Fecha dropdown ao clicar fora
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsCategoryDropdownOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const formatMoney = (v: number) => v.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });

  const refreshData = async () => {
    if (state.currentUser?.companyId) {
      const data = await fetchCompleteCompanyData(state.currentUser.companyId);
      if (data) setState(prev => ({ ...prev, ...data }));
    }
  };

  const handleOpenForm = () => {
    setEditingId(null);
    setFormData({
      type: activeTab,
      value: '',
      date: new Date().toISOString().split('T')[0],
      reference: '',
      category: state.financeCategories[0] || 'Geral'
    });
    setShowForm(true);
  };

  const handleEdit = (item: any) => {
    setEditingId(item.id);
    setFormData({
      type: item.type as 'in' | 'out',
      value: String(item.value).replace('.', ','),
      date: item.date,
      reference: item.reference,
      category: item.category
    });
    setShowForm(true);
  };

  const handleSaveMove = async (e: React.FormEvent) => {
    e.preventDefault();
    const val = parseFloat(formData.value.replace(',', '.'));
    if (isNaN(val) || val <= 0) return notify("Valor inválido", "error");

    setIsLoading(true);
    try {
      await dbSave('cash_flow', {
        id: editingId || undefined,
        companyId: state.currentUser?.companyId,
        type: formData.type,
        value: val,
        date: formData.date,
        reference: formData.reference || (formData.type === 'in' ? 'Receita Diversa' : 'Despesa Diversa'),
        category: formData.category
      });
      await refreshData();
      setShowForm(false);
      setEditingId(null);
      notify(editingId ? "Lançamento atualizado" : "Lançamento efetivado");
    } catch (e: any) {
      console.error(e);
      notify("Erro na gravação.", "error");
    } finally {
      setIsLoading(false);
    }
  };

  const toggleCategory = (category: string) => {
    setCategoryFilter(prev => 
      prev.includes(category) 
        ? prev.filter(c => c !== category) 
        : [...prev, category]
    );
  };

  // Lógica de Filtragem Universal (Aplicada tanto para a tabela quanto para os cards de resumo)
  const filterList = (list: any[]) => {
    return list.filter(item => {
      const matchesSearch = item.reference.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesCategory = categoryFilter.length === 0 || categoryFilter.includes(item.category);
      const matchesDate = (!startDate || item.date >= startDate) && (!endDate || item.date <= endDate);
      return matchesSearch && matchesCategory && matchesDate;
    });
  };

  const filteredIn = useMemo(() => filterList(state.cashIn), [state.cashIn, searchQuery, categoryFilter, startDate, endDate]);
  const filteredOut = useMemo(() => filterList(state.cashOut), [state.cashOut, searchQuery, categoryFilter, startDate, endDate]);

  const totalIn = useMemo(() => filteredIn.reduce((acc, c) => acc + c.value, 0), [filteredIn]);
  const totalOut = useMemo(() => filteredOut.reduce((acc, c) => acc + c.value, 0), [filteredOut]);
  const totalBalance = totalIn - totalOut;

  const filteredData = activeTab === 'in' ? filteredIn : filteredOut;

  return (
    <div className="space-y-6">
      <header className="flex justify-between items-center">
        <div>
          <h2 className="text-xl font-black text-slate-900 uppercase">Fluxo de Caixa</h2>
          <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">Saldos Unificados Cloud</p>
        </div>
        <button onClick={handleOpenForm} className="bg-slate-900 text-white px-6 py-3 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-emerald-600 transition-all flex items-center gap-2 shadow-xl">
          <Plus size={18} /> Novo Registro
        </button>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-[32px] border border-slate-100 shadow-sm flex items-center gap-4">
           <div className="w-12 h-12 bg-emerald-50 text-emerald-600 rounded-xl flex items-center justify-center"><ArrowUpCircle size={24} /></div>
           <div>
             <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest">
               Receitas {(startDate || endDate || categoryFilter.length > 0 || searchQuery) ? 'Filtradas' : 'Totais'}
             </p>
             <p className="text-lg font-black text-emerald-600">{formatMoney(totalIn)}</p>
           </div>
        </div>
        <div className="bg-white p-6 rounded-[32px] border border-slate-100 shadow-sm flex items-center gap-4">
           <div className="w-12 h-12 bg-rose-50 text-rose-600 rounded-xl flex items-center justify-center"><ArrowDownCircle size={24} /></div>
           <div>
             <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest">
               Despesas {(startDate || endDate || categoryFilter.length > 0 || searchQuery) ? 'Filtradas' : 'Totais'}
             </p>
             <p className="text-lg font-black text-rose-600">{formatMoney(totalOut)}</p>
           </div>
        </div>
        <div className="bg-slate-900 text-white p-6 rounded-[32px] shadow-2xl flex items-center gap-4 border border-white/5">
           <div className="w-12 h-12 bg-white/10 text-emerald-400 rounded-xl flex items-center justify-center"><Wallet size={24} /></div>
           <div>
             <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Saldo no Período</p>
             <p className={`text-lg font-black ${totalBalance >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>{formatMoney(totalBalance)}</p>
           </div>
        </div>
      </div>

      {/* Barra de Filtros Atualizada com Multi-Checkbox */}
      <div className="bg-white p-6 rounded-[32px] border border-slate-200 shadow-sm space-y-4">
        <div className="flex items-center gap-2 text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">
          <Filter size={14}/> Filtragem e Busca Avançada
        </div>
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          <div className="relative">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={16} />
            <input 
              className="w-full bg-slate-50 border border-slate-100 pl-11 pr-4 py-3 rounded-2xl text-[10px] font-black uppercase outline-none focus:bg-white focus:border-slate-900 transition-all" 
              placeholder="BUSCAR REFERÊNCIA..." 
              value={searchQuery}
              onChange={e => setSearchQuery(e.target.value)}
            />
          </div>

          {/* Multi-Select Dropdown */}
          <div className="relative" ref={dropdownRef}>
            <button 
              onClick={() => setIsCategoryDropdownOpen(!isCategoryDropdownOpen)}
              className="w-full bg-slate-50 border border-slate-100 p-3 rounded-2xl text-[10px] font-black uppercase flex items-center justify-between hover:bg-white hover:border-slate-900 transition-all text-left"
            >
              <span className="truncate">
                {categoryFilter.length === 0 ? 'TODAS AS CATEGORIAS' : `${categoryFilter.length} SELECIONADAS`}
              </span>
              <ChevronDown size={14} className={`transition-transform ${isCategoryDropdownOpen ? 'rotate-180' : ''}`} />
            </button>

            {isCategoryDropdownOpen && (
              <div className="absolute top-full left-0 right-0 mt-2 bg-white border border-slate-200 rounded-2xl shadow-2xl z-50 p-3 space-y-1 max-h-60 overflow-y-auto animate-in fade-in slide-in-from-top-2">
                <button 
                  onClick={() => setCategoryFilter([])}
                  className="w-full text-left p-2 rounded-xl text-[9px] font-black uppercase text-rose-500 hover:bg-rose-50 transition-colors mb-1"
                >
                  LIMPAR SELEÇÃO
                </button>
                {state.financeCategories.map(cat => (
                  <label 
                    key={cat} 
                    className="flex items-center gap-3 p-3 rounded-xl hover:bg-slate-50 cursor-pointer transition-colors group"
                  >
                    <input 
                      type="checkbox" 
                      className="hidden" 
                      checked={categoryFilter.includes(cat)} 
                      onChange={() => toggleCategory(cat)} 
                    />
                    <div className={`transition-all ${categoryFilter.includes(cat) ? 'text-emerald-600 scale-110' : 'text-slate-300 group-hover:text-slate-400'}`}>
                      {categoryFilter.includes(cat) ? <CheckSquare size={18} /> : <Square size={18} />}
                    </div>
                    <span className={`text-[10px] font-black uppercase transition-colors ${categoryFilter.includes(cat) ? 'text-slate-900' : 'text-slate-500'}`}>
                      {cat}
                    </span>
                  </label>
                ))}
              </div>
            )}
          </div>

          <div className="flex items-center gap-2 bg-slate-50 px-4 py-2 rounded-2xl border border-slate-100">
             <Calendar size={14} className="text-slate-400" />
             <div className="flex flex-col">
               <label className="text-[7px] font-black text-slate-400 uppercase">DE:</label>
               <input type="date" className="bg-transparent text-[10px] font-black outline-none" value={startDate} onChange={e => setStartDate(e.target.value)} />
             </div>
          </div>
          <div className="flex items-center gap-2 bg-slate-50 px-4 py-2 rounded-2xl border border-slate-100">
             <Calendar size={14} className="text-slate-400" />
             <div className="flex flex-col">
               <label className="text-[7px] font-black text-slate-400 uppercase">ATÉ:</label>
               <input type="date" className="bg-transparent text-[10px] font-black outline-none" value={endDate} onChange={e => setEndDate(e.target.value)} />
             </div>
          </div>
        </div>
        {(searchQuery || categoryFilter.length > 0 || startDate || endDate) && (
          <button 
            onClick={() => { setSearchQuery(''); setCategoryFilter([]); setStartDate(''); setEndDate(''); }}
            className="text-[9px] font-black text-rose-500 uppercase flex items-center gap-2 hover:opacity-70"
          >
            <X size={14}/> Limpar filtros selecionados
          </button>
        )}
      </div>

      <div className="bg-white rounded-[32px] border border-slate-100 shadow-sm overflow-hidden">
        <div className="flex bg-slate-50 p-2 border-b border-slate-100">
           <button onClick={() => setActiveTab('in')} className={`flex-1 py-4 text-[10px] font-black uppercase rounded-2xl transition-all ${activeTab === 'in' ? 'bg-white text-emerald-600 shadow-md' : 'text-slate-400 hover:text-slate-600'}`}>Entradas</button>
           <button onClick={() => setActiveTab('out')} className={`flex-1 py-4 text-[10px] font-black uppercase rounded-2xl transition-all ${activeTab === 'out' ? 'bg-white text-rose-600 shadow-md' : 'text-slate-400 hover:text-slate-600'}`}>Saídas</button>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
                <tr className="text-[9px] font-black uppercase text-slate-400 bg-slate-50/50 border-b border-slate-100">
                  <th className="px-8 py-5">Data</th>
                  <th className="px-8 py-5">Referência</th>
                  <th className="px-8 py-5">Categoria</th>
                  <th className="px-8 py-5 text-right">Valor</th>
                  <th className="px-8 py-5 text-center">Ações</th>
                </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
                {filteredData.length === 0 ? (
                  <tr><td colSpan={5} className="px-8 py-20 text-center italic text-slate-300 uppercase text-[10px] font-black">Nenhum lançamento encontrado para os critérios de busca</td></tr>
                ) : (
                  filteredData.map(item => (
                    <tr key={item.id} className="hover:bg-slate-50/30 transition-colors group">
                      <td className="px-8 py-4 text-[10px] font-bold text-slate-500">{item.date.split('-').reverse().join('/')}</td>
                      <td className="px-8 py-4 text-[10px] font-black uppercase text-slate-800">{item.reference}</td>
                      <td className="px-8 py-4"><span className="text-[8px] font-black uppercase bg-slate-100 px-3 py-1 rounded-lg text-slate-500">{item.category}</span></td>
                      <td className={`px-8 py-4 text-right font-black text-sm ${activeTab === 'in' ? 'text-emerald-600' : 'text-rose-600'}`}>{formatMoney(item.value)}</td>
                      <td className="px-8 py-4 text-center">
                        <div className="flex items-center justify-center gap-1">
                          <button onClick={() => handleEdit(item)} className="p-2 text-slate-300 hover:text-blue-600 transition-colors">
                            <Edit2 size={16} />
                          </button>
                          <button onClick={() => setConfirmDelete({ isOpen: true, id: item.id })} className="p-2 text-slate-300 hover:text-rose-600 transition-colors">
                            <Trash2 size={16} />
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))
                )}
            </tbody>
            {filteredData.length > 0 && (
              <tfoot className="bg-slate-50/80 border-t border-slate-100">
                <tr>
                  <td colSpan={3} className="px-8 py-4 text-[9px] font-black uppercase text-slate-400">Total na Lista ({activeTab === 'in' ? 'Receitas' : 'Despesas'})</td>
                  <td className={`px-8 py-4 text-right font-black text-sm ${activeTab === 'in' ? 'text-emerald-600' : 'text-rose-600'}`}>{formatMoney(activeTab === 'in' ? totalIn : totalOut)}</td>
                  <td></td>
                </tr>
              </tfoot>
            )}
          </table>
        </div>
      </div>

      {showForm && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[100] flex items-center justify-center p-4">
           <form onSubmit={handleSaveMove} className="bg-white rounded-[40px] w-full max-w-sm p-10 space-y-6 shadow-2xl animate-in zoom-in-95 border border-slate-100">
              <div className="flex justify-between items-center border-b border-slate-50 pb-5">
                <div>
                   <h3 className="font-black uppercase text-xs text-slate-900">{editingId ? 'Editar Lançamento' : 'Novo Lançamento'}</h3>
                   <p className={`text-[9px] font-bold uppercase mt-1 ${formData.type === 'in' ? 'text-emerald-500' : 'text-rose-500'}`}>
                     {formData.type === 'in' ? 'Entrada de Receita' : 'Saída de Despesa'}
                   </p>
                </div>
                <button type="button" onClick={() => { setShowForm(false); setEditingId(null); }} className="p-2 hover:bg-slate-50 rounded-full transition-all"><X size={20}/></button>
              </div>

              <div className="flex bg-slate-100 p-1.5 rounded-2xl">
                 <button 
                  type="button" 
                  onClick={() => setFormData({...formData, type: 'in'})}
                  className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-xl text-[9px] font-black uppercase transition-all ${formData.type === 'in' ? 'bg-white text-emerald-600 shadow-sm' : 'text-slate-400'}`}
                 >
                   <ArrowUpCircle size={14}/> Entrada
                 </button>
                 <button 
                  type="button" 
                  onClick={() => setFormData({...formData, type: 'out'})}
                  className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-xl text-[9px] font-black uppercase transition-all ${formData.type === 'out' ? 'bg-white text-rose-600 shadow-sm' : 'text-slate-400'}`}
                 >
                   <ArrowDownCircle size={14}/> Saída
                 </button>
              </div>

              <div className="space-y-4">
                 <div className="space-y-1">
                    <label className="text-[9px] font-black text-slate-400 uppercase ml-1">VALOR DO LANÇAMENTO</label>
                    <input 
                      type="text"
                      required 
                      className={`w-full bg-slate-50 border border-slate-200 p-4 rounded-2xl font-black text-xs outline-none focus:bg-white transition-all ${formData.type === 'in' ? 'focus:border-emerald-500' : 'focus:border-rose-500'}`} 
                      placeholder="0,00" 
                      value={formData.value} 
                      onChange={e => setFormData({...formData, value: e.target.value})} 
                    />
                 </div>
                 <div className="space-y-1">
                    <label className="text-[9px] font-black text-slate-400 uppercase ml-1">DATA DE COMPETÊNCIA</label>
                    <input type="date" required className="w-full bg-slate-50 border border-slate-200 p-4 rounded-2xl font-black text-xs outline-none focus:bg-white" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} />
                 </div>
                 <div className="space-y-1">
                    <label className="text-[9px] font-black text-slate-400 uppercase ml-1">REFERÊNCIA DO TÍTULO</label>
                    <input className="w-full bg-slate-50 border border-slate-200 p-4 rounded-2xl font-black text-xs uppercase outline-none focus:bg-white" placeholder="EX: PAGAMENTO DE COMBUSTÍVEL" value={formData.reference} onChange={e => setFormData({...formData, reference: e.target.value.toUpperCase()})} />
                 </div>
                 <div className="space-y-1">
                    <label className="text-[9px] font-black text-slate-400 uppercase ml-1">CATEGORIA</label>
                    <select className="w-full bg-slate-50 border border-slate-200 p-4 rounded-2xl font-black text-xs outline-none" value={formData.category} onChange={e => setFormData({...formData, category: e.target.value})}>
                       {state.financeCategories.map(c => <option key={c} value={c}>{c.toUpperCase()}</option>)}
                    </select>
                 </div>
                 <button 
                  disabled={isLoading} 
                  className={`w-full text-white py-4 rounded-2xl font-black uppercase text-[10px] tracking-widest transition-all flex items-center justify-center gap-3 shadow-xl ${formData.type === 'in' ? 'bg-emerald-600 hover:bg-emerald-700' : 'bg-rose-600 hover:bg-rose-700'}`}
                 >
                   {isLoading ? <Loader2 className="animate-spin" size={16} /> : (editingId ? 'SALVAR ALTERAÇÕES' : `EFETIVAR ${formData.type === 'in' ? 'RECEITA' : 'DESPESA'}`)}
                 </button>
              </div>
           </form>
        </div>
      )}
      <ConfirmationModal isOpen={!!confirmDelete?.isOpen} onClose={() => setConfirmDelete(null)} onConfirm={async () => { await dbDelete('cash_flow', confirmDelete!.id); await refreshData(); notify("Lançamento removido"); }} title="Excluir" message="Remover permanentemente do banco?" />
    </div>
  );
};

export default Finance;

import React, { useState, useMemo } from 'react';
import { AppState, Employee, AttendanceRecord } from '../types';
import { Users, UserPlus, X, ChevronRight, ChevronLeft, Edit2, Trash2, Loader2, Save, Fingerprint, Smartphone, MapPin, CreditCard, Power, UserX, AlertCircle, Clock, Briefcase, HeartPulse, ShieldAlert, Palmtree, Mail, DollarSign, Calendar, Users2, CheckCircle2, Wallet } from 'lucide-react';
import { dbSave, dbDelete, fetchCompleteCompanyData } from '../lib/supabase';

interface EmployeesProps {
  state: AppState;
  setState: React.Dispatch<React.SetStateAction<AppState>>;
  notify: (msg: string, type?: 'success' | 'error') => void;
}

const Employees: React.FC<EmployeesProps> = ({ state, setState, notify }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [currentCalendarDate, setCurrentCalendarDate] = useState(new Date());
  const [showInactive, setShowInactive] = useState(false);
  const [showTimeModal, setShowTimeModal] = useState<{ emp: Employee, date: string, record?: AttendanceRecord } | null>(null);

  const initialFormState = { 
    name: '', 
    role: '', 
    defaultValue: '0', 
    cpf: '', 
    phone: '', 
    pixKey: '', 
    address: '',
    paymentModality: 'DIARIA' as 'DIARIA' | 'CLT',
    workload: '44H SEMANAIS',
    startTime: '08:00',
    breakStart: '12:00',
    breakEnd: '13:00',
    endTime: '17:00'
  };

  const [employeeForm, setEmployeeForm] = useState(initialFormState);

  const [pointForm, setPointForm] = useState({
    clockIn: '',
    breakStart: '',
    breakEnd: '',
    clockOut: '',
    status: 'present' as AttendanceRecord['status'],
    observation: ''
  });

  const refreshData = async () => {
    if (state.currentUser?.companyId) {
      const data = await fetchCompleteCompanyData(state.currentUser.companyId);
      if (data) setState(prev => ({ ...prev, ...data }));
    }
  };

  const getVirtualStatus = (record: AttendanceRecord): AttendanceRecord['status'] => {
    if (record.status !== 'absent') return record.status;
    const obs = record.discountObservation || '';
    if (obs.startsWith('[AT]')) return 'atestado';
    if (obs.startsWith('[FJ]')) return 'justified';
    if (obs.startsWith('[FE]')) return 'vacation';
    return 'absent';
  };

  const handleToggleAttendance = async (empId: string, date: string) => {
    const emp = state.employees.find(e => e.id === empId);
    if (!emp) return;
    if (emp.status === 'inactive') return notify("Não é possível lançar frequência para inativos", "error");

    const existing = state.attendanceRecords.find(r => r.employeeId === empId && r.date === date);

    if (emp.paymentModality === 'CLT') {
      const virtualStatus = existing ? getVirtualStatus(existing) : 'present';
      const cleanObs = (existing?.discountObservation || '').replace(/^\[(AT|FJ|FE)\]\s*/, '');

      setPointForm({
        clockIn: existing?.clockIn || emp.startTime || '08:00',
        breakStart: existing?.breakStart || emp.breakStart || '12:00',
        breakEnd: existing?.breakEnd || emp.breakEnd || '13:00',
        clockOut: existing?.clockOut || emp.endTime || '17:00',
        status: virtualStatus,
        observation: cleanObs
      });
      setShowTimeModal({ emp, date, record: existing });
      return;
    }

    try {
      if (!existing) {
        await dbSave('attendance_records', {
          companyId: state.currentUser?.companyId,
          employeeId: empId,
          date,
          status: 'present',
          value: Number(emp.defaultValue) || 0,
          paymentStatus: 'pendente'
        });
      } else if (existing.status === 'present') {
        await dbSave('attendance_records', { ...existing, status: 'partial', value: (Number(emp.defaultValue) || 0) / 2 });
      } else if (existing.status === 'partial') {
        await dbSave('attendance_records', { ...existing, status: 'absent', value: 0 });
      } else {
        await dbDelete('attendance_records', existing.id);
      }
      await refreshData();
    } catch (e) { 
      notify("Erro ao sincronizar presença", "error"); 
    }
  };

  const handleSavePoint = async () => {
    if (!showTimeModal) return;
    const { emp, date, record } = showTimeModal;

    setIsLoading(true);
    try {
      let dbStatus: AttendanceRecord['status'] = 'absent';
      let prefix = '';

      if (pointForm.status === 'present' || pointForm.status === 'partial') {
        dbStatus = pointForm.status;
      } else if (pointForm.status === 'atestado') {
        dbStatus = 'absent';
        prefix = '[AT] ';
      } else if (pointForm.status === 'justified') {
        dbStatus = 'absent';
        prefix = '[FJ] ';
      } else if (pointForm.status === 'vacation') {
        dbStatus = 'absent';
        prefix = '[FE] ';
      }

      const finalObservation = prefix + (pointForm.observation || '');
      const isWorking = dbStatus === 'present' || dbStatus === 'partial';

      let finalValue = 0;
      if (emp.paymentModality === 'CLT') {
        if (['present', 'partial', 'atestado', 'justified', 'vacation'].includes(pointForm.status)) {
          finalValue = Number(emp.defaultValue) || 0;
        }
      }

      await dbSave('attendance_records', {
        id: record?.id || undefined,
        companyId: state.currentUser?.companyId,
        employeeId: emp.id,
        date,
        status: dbStatus,
        value: finalValue,
        paymentStatus: record?.paymentStatus || 'pendente',
        clockIn: isWorking ? (pointForm.clockIn || null) : null,
        breakStart: isWorking ? (pointForm.breakStart || null) : null,
        breakEnd: isWorking ? (pointForm.breakEnd || null) : null,
        clockOut: isWorking ? (pointForm.clockOut || null) : null,
        discountObservation: finalObservation || null
      });

      await refreshData();
      setShowTimeModal(null);
      notify("Registro salvo com sucesso");
    } catch (e) { 
      notify("Erro ao salvar registro de ponto", "error"); 
    } finally { 
      setIsLoading(false); 
    }
  };

  const handleToggleStatus = async (emp: Employee) => {
    setIsLoading(true);
    try {
      const newStatus = emp.status === 'active' ? 'inactive' : 'active';
      await dbSave('employees', { id: emp.id, status: newStatus });
      await refreshData();
      notify(`Colaborador ${newStatus === 'active' ? 'Reativado' : 'Inativado'}`);
    } catch (e) { notify("Falha ao atualizar status", "error"); } finally { setIsLoading(false); }
  };

  const handleSaveEmployee = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!employeeForm.name) return notify("Nome completo é obrigatório", "error");
    if (!employeeForm.role) return notify("Selecione um Cargo / Função", "error");

    setIsLoading(true);
    try {
      const finalValue = parseFloat(employeeForm.defaultValue.replace(',', '.')) || 0;

      await dbSave('employees', {
        id: editingId || undefined,
        companyId: state.currentUser?.companyId,
        name: employeeForm.name.toUpperCase(),
        role: employeeForm.role.toUpperCase(),
        defaultValue: finalValue,
        cpf: employeeForm.cpf || null,
        phone: employeeForm.phone || null,
        pixKey: employeeForm.pixKey || null,
        address: employeeForm.address.toUpperCase() || null,
        status: editingId ? (state.employees.find(e => e.id === editingId)?.status || 'active') : 'active',
        paymentModality: employeeForm.paymentModality,
        workload: employeeForm.workload.toUpperCase() || null,
        startTime: employeeForm.startTime || null,
        breakStart: employeeForm.breakStart || null,
        breakEnd: employeeForm.breakEnd || null,
        endTime: employeeForm.endTime || null
      });
      await refreshData();
      setShowForm(false);
      setEditingId(null);
      setEmployeeForm(initialFormState);
      notify(editingId ? "Cadastro atualizado" : "Novo colaborador integrado");
    } catch (e: any) { 
      notify("Falha na sincronização.", "error"); 
    } finally { 
      setIsLoading(false); 
    }
  };

  const handleEdit = (emp: Employee) => {
    setEditingId(emp.id);
    setEmployeeForm({
      name: emp.name,
      role: emp.role,
      defaultValue: String(emp.defaultValue || 0),
      cpf: emp.cpf || '',
      phone: emp.phone || '',
      pixKey: emp.pixKey || '',
      address: emp.address || '',
      paymentModality: emp.paymentModality || 'DIARIA',
      workload: emp.workload || '44H SEMANAIS',
      startTime: emp.startTime || '08:00',
      breakStart: emp.breakStart || '12:00',
      breakEnd: emp.breakEnd || '13:00',
      endTime: emp.endTime || '17:00'
    });
    setShowForm(true);
  };

  const daysInMonth = useMemo(() => new Date(currentCalendarDate.getFullYear(), currentCalendarDate.getMonth() + 1, 0).getDate(), [currentCalendarDate]);
  const calendarDays = Array.from({ length: daysInMonth }, (_, i) => i + 1);
  const filteredEmployees = state.employees.filter(e => showInactive || e.status === 'active');

  // Cálculos de Resumo Financeiro do Mês Visualizado
  const monthSummary = useMemo(() => {
    const yearMonth = `${currentCalendarDate.getFullYear()}-${String(currentCalendarDate.getMonth() + 1).padStart(2, '0')}`;
    const visibleEmpIds = new Set(filteredEmployees.map(e => e.id));

    let paid = 0;
    let pending = 0;

    state.attendanceRecords.forEach(record => {
      if (record.date.startsWith(yearMonth) && visibleEmpIds.has(record.employeeId)) {
        const netValue = record.value - (record.discountValue || 0);
        if (record.paymentStatus === 'pago') {
          paid += netValue;
        } else {
          pending += netValue;
        }
      }
    });

    return { paid, pending };
  }, [state.attendanceRecords, filteredEmployees, currentCalendarDate]);

  const formatMoney = (v: number) => v.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });

  const getAttendanceLabel = (record: AttendanceRecord | undefined, emp: Employee) => {
    if (!record) return '-';
    const virtualStatus = getVirtualStatus(record);
    if (emp.paymentModality === 'CLT') {
      switch(virtualStatus) {
        case 'present': return record.clockIn || 'P';
        case 'atestado': return 'AT';
        case 'justified': return 'FJ';
        case 'vacation': return 'FE';
        case 'absent': return 'F';
        case 'partial': return 'P';
        default: return '-';
      }
    } else {
      switch(virtualStatus) {
        case 'present': return 'P';
        case 'partial': return 'H';
        case 'absent': return 'F';
        case 'atestado': return 'AT';
        case 'justified': return 'FJ';
        case 'vacation': return 'FE';
        default: return '-';
      }
    }
  };

  return (
    <div className="space-y-6 pb-24">
      <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-xl font-black text-slate-900 uppercase tracking-tight">Equipe & Frequência</h2>
          <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">Gestão de Pessoal e Presença</p>
        </div>
        <div className="flex gap-2 w-full md:w-auto">
          <button onClick={() => setShowInactive(!showInactive)} className="flex-1 md:flex-none px-4 py-2.5 bg-white border border-slate-200 rounded-xl font-black text-[9px] uppercase transition-all shadow-sm">
             {showInactive ? 'Filtrar Ativos' : 'Exibir Todos'}
          </button>
          <button onClick={() => { setEditingId(null); setEmployeeForm(initialFormState); setShowForm(true); }} className="flex-1 md:flex-none bg-slate-900 text-white px-5 py-3 rounded-xl font-black text-[9px] uppercase shadow-lg hover:bg-emerald-600 transition-all flex items-center justify-center gap-2">
             <UserPlus size={16}/> Novo Cadastro
          </button>
        </div>
      </header>

      {/* Cards de Resumo Financeiro de Equipe */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div className="bg-white p-6 rounded-[32px] border border-slate-100 shadow-sm flex items-center gap-5 transition-all hover:border-emerald-200">
           <div className="w-14 h-14 bg-emerald-50 text-emerald-600 rounded-2xl flex items-center justify-center shadow-inner"><CheckCircle2 size={28} /></div>
           <div>
              <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">Total Já Pago (Mês)</p>
              <h3 className="text-2xl font-black text-emerald-600 tracking-tighter">{formatMoney(monthSummary.paid)}</h3>
           </div>
        </div>
        <div className="bg-slate-900 p-6 rounded-[32px] border border-white/5 shadow-2xl flex items-center gap-5 transition-all hover:bg-slate-800">
           <div className="w-14 h-14 bg-white/10 text-amber-400 rounded-2xl flex items-center justify-center shadow-inner"><Wallet size={28} /></div>
           <div>
              <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest mb-1">Saldo Pendente Acumulado</p>
              <h3 className="text-2xl font-black text-white tracking-tighter">{formatMoney(monthSummary.pending)}</h3>
           </div>
        </div>
      </div>

      <div className="bg-white rounded-[32px] border border-slate-200 shadow-sm overflow-hidden animate-in fade-in duration-300">
        <div className="p-4 md:p-6 border-b bg-slate-50 flex flex-col md:flex-row items-center justify-between gap-4">
          <div className="flex items-center gap-4">
            <button onClick={() => setCurrentCalendarDate(new Date(currentCalendarDate.setMonth(currentCalendarDate.getMonth() - 1)))} className="p-2 hover:bg-white rounded-lg border border-transparent hover:border-slate-200"><ChevronLeft size={18} /></button>
            <h3 className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-900">{currentCalendarDate.toLocaleString('pt-BR', { month: 'long', year: 'numeric' }).toUpperCase()}</h3>
            <button onClick={() => setCurrentCalendarDate(new Date(currentCalendarDate.setMonth(currentCalendarDate.getMonth() + 1)))} className="p-2 hover:bg-white rounded-lg border border-transparent hover:border-slate-200"><ChevronRight size={18} /></button>
          </div>
          <div className="hidden sm:flex items-center gap-4 text-slate-400 font-black text-[8px] uppercase tracking-widest">
             Legenda: <span className="text-emerald-500">P=Presença</span> • <span className="text-rose-500">F=Falta</span> • <span className="text-purple-500">AT=Atestado</span> • <span className="text-blue-500">FJ=Justificada</span> • <span className="text-amber-500">FE=Férias</span>
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full min-w-[800px] border-collapse">
            <thead className="bg-slate-50 text-[9px] font-black text-slate-400 uppercase border-b">
              <tr>
                <th className="sticky left-0 z-20 bg-slate-50 p-4 text-left border-r shadow-[4px_0_10px_-4px_rgba(0,0,0,0.1)] min-w-[220px]">Colaborador</th>
                {calendarDays.map(day => {
                   const dateStr = `${currentCalendarDate.getFullYear()}-${String(currentCalendarDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
