import { useState, useEffect, useCallback, useRef } from 'react';
import { AppState, UserRole } from './types';
import { INITIAL_STATE } from './constants';
import { supabase, fetchUserProfile, fetchCompleteCompanyData, signOut } from './lib/supabase';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import Production from './components/Production';
import Finance from './components/Finance';
import Inventory from './components/Inventory';
import Employees from './components/Employees';
import Settings from './components/Settings';
import Login from './components/Login';
import Analytics from './components/Analytics';
import Management from './components/Management';
import Support from './components/Support';
import ConfirmationModal from './components/ConfirmationModal';
import { RefreshCw, LogOut, AlertCircle, X, CheckCircle2 } from 'lucide-react';

const App = () => {
  const [isInitializing, setIsInitializing] = useState(true);
  const [state, setState] = useState<AppState>(INITIAL_STATE);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [showLogoutConfirm, setShowLogoutConfirm] = useState(false);
  const [notification, setNotification] = useState<{message: string, type: 'success' | 'error'} | null>(null);
  const [initError, setInitError] = useState<string | null>(null);

  const currentUserRef = useRef<string | null>(null);

  const notify = (message: string, type: 'success' | 'error' = 'success') => {
    setNotification({ message, type });
    setTimeout(() => setNotification(null), 3000);
  };

  const syncData = useCallback(async (userId: string, retryCount = 0) => {
    try {
      const profile = await fetchUserProfile(userId);

      if (!profile) {
        if (retryCount < 2) { 
          setTimeout(() => syncData(userId, retryCount + 1), 1500);
          return;
        }
        setInitError("PERFIL OPERACIONAL NÃO ENCONTRADO.");
        setIsInitializing(false);
        return;
      }

      if (!profile.company_id) {
        setInitError("USUÁRIO SEM UNIDADE.");
        setIsInitializing(false);
        return;
      }

      const companyData = await fetchCompleteCompanyData(profile.company_id);

      setState(prev => ({
        ...prev,
        currentUser: {
          id: profile.id,
          email: profile.email || '',
          name: profile.full_name || 'Usuário',
          role: profile.role as UserRole || UserRole.OPERATIONAL,
          companyId: profile.company_id,
          status: profile.status as 'ativo' | 'suspenso' || 'ativo',
          permissions: profile.permissions || INITIAL_STATE.users[0].permissions
        },
        ...(companyData || {})
      }));

      currentUserRef.current = userId;
      setInitError(null);
      setIsInitializing(false);
    } catch (e: any) {
      setInitError("FALHA DE COMUNICAÇÃO.");
      setIsInitializing(false);
    }
  }, []);

  useEffect(() => {
    const initAuth = async () => {
      try {
        const { data: { session } } = await supabase.auth.getSession();
        if (session?.user) {
          currentUserRef.current = session.user.id;
          await syncData(session.user.id);
        } else {
          setIsInitializing(false);
        }
      } catch (e) {
        setIsInitializing(false);
      }
    };
    initAuth();

    const { data: { subscription } } = supabase.auth.onAuthStateChange((event, session) => {
      if (event === 'SIGNED_IN' && session?.user) {
        if (currentUserRef.current !== session.user.id) {
          setIsInitializing(true);
          syncData(session.user.id);
        }
      } else if (event === 'SIGNED_OUT') {
        currentUserRef.current = null;
        setState({ ...INITIAL_STATE, currentUser: null });
        setIsInitializing(false);
      }
    });
    return () => subscription.unsubscribe();
  }, [syncData]);

  if (isInitializing) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-[#020617] text-center p-6">
        <div className="w-16 h-16 border-4 border-slate-800 border-t-emerald-500 rounded-full animate-spin shadow-[0_0_20px_rgba(16,185,129,0.2)]" />
        <div className="mt-8 space-y-2">
          <h2 className="font-black text-white uppercase tracking-[0.4em] text-[11px]">Fera Service Cloud</h2>
        </div>
      </div>
    );
  }

  if (initError) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-[#020617] p-6">
        <div className="bg-slate-900 border border-white/10 p-10 rounded-[40px] max-w-sm w-full text-center shadow-2xl">
           <AlertCircle size={32} className="text-rose-500 mx-auto mb-6" />
           <p className="text-[11px] text-slate-400 font-bold uppercase mb-10">{initError}</p>
           <button onClick={() => window.location.reload()} className="w-full bg-white text-slate-900 py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl">Reconectar</button>
        </div>
      </div>
    );
  }

  if (!state.currentUser) return <Login onLogin={() => {}} users={[]} />;

  return (
    <>
      <Layout activeTab={activeTab} setActiveTab={setActiveTab} userRole={state.currentUser.role} user={state.currentUser} onLogout={() => setShowLogoutConfirm(true)}>
        {(() => {
          const props = { state, setState, setActiveTab, notify };
          switch (activeTab) {
            case 'dashboard': return <Dashboard {...props} />;
            case 'production': return <Production {...props} />;
            case 'finance': return <Finance {...props} />;
            case 'inventory': return <Inventory {...props} />;
            case 'employees': return <Employees {...props} />;
            case 'analytics': return <Analytics {...props} />;
            case 'management': return <Management {...props} />;
            case 'settings': return <Settings {...props} />;
            case 'support': return <Support {...props} />;
            default: return <Dashboard {...props} />;
          }
        })()}
      </Layout>

      {notification && (
        <div className={`fixed bottom-8 left-1/2 -translate-x-1/2 z-[1000] px-6 py-4 rounded-2xl shadow-2xl flex items-center gap-4 animate-in slide-in-from-bottom-4 border ${notification.type === 'success' ? 'bg-emerald-600 border-emerald-500 text-white' : 'bg-rose-600 border-rose-500 text-white'}`}>
           <p className="text-[10px] font-black uppercase tracking-widest">{notification.message}</p>
        </div>
      )}

      <ConfirmationModal isOpen={showLogoutConfirm} onClose={() => setShowLogoutConfirm(false)} onConfirm={async () => { await signOut(); setShowLogoutConfirm(false); }} title="Sair do Sistema" message="Deseja encerrar sua sessão segura?" confirmText="Sair" type="warning" />
    </>
  );
};

export default App;

import React, { useState } from 'react';
import { AppState, SupportRequest } from '../types';
import { LifeBuoy, Plus, Loader2, CheckCircle2, Clock, Trash2, X } from 'lucide-react';
import { dbSave, dbDelete, fetchCompleteCompanyData } from '../lib/supabase';

interface SupportProps {
  state: AppState;
  setState: React.Dispatch<React.SetStateAction<AppState>>;
  notify: (msg: string, type?: 'success' | 'error') => void;
}

const Support: React.FC<SupportProps> = ({ state, setState, notify }) => {
  const [description, setDescription] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [showForm, setShowForm] = useState(false);

  const refreshData = async () => {
    if (state.currentUser?.companyId) {
      const data = await fetchCompleteCompanyData(state.currentUser.companyId);
      if (data) setState(prev => ({ ...prev, ...data }));
    }
  };

  const handleAddRequest = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!description.trim()) return notify("Descreva sua solicitação", "error");

    setIsLoading(true);
    try {
      await dbSave('support_requests', {
        companyId: state.currentUser?.companyId,
        description: description.toUpperCase(),
        status: 'pendente'
      });
      await refreshData();
      setDescription('');
      setShowForm(false);
      notify("Solicitação enviada com sucesso!");
    } catch (e) {
      notify("Erro ao enviar solicitação", "error");
    } finally {
      setIsLoading(false);
    }
  };

  const toggleStatus = async (request: SupportRequest) => {
    setIsLoading(true);
    try {
      const newStatus = request.status === 'pendente' ? 'concluido' : 'pendente';
      await dbSave('support_requests', { ...request, status: newStatus });
      await refreshData();
      notify(`Status atualizado para ${newStatus.toUpperCase()}`);
    } catch (e) {
      notify("Erro ao atualizar status", "error");
    } finally {
      setIsLoading(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm("Deseja realmente excluir este ticket?")) return;
    setIsLoading(true);
    try {
      await dbDelete('support_requests', id);
      await refreshData();
      notify("Ticket removido");
    } catch (e) {
      notify("Erro ao excluir", "error");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="space-y-6">
      <header className="flex justify-between items-center">
        <div>
          <h2 className="text-xl font-black text-slate-900 uppercase tracking-tight">Central de Suporte</h2>
          <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">Gestão de Tickets e Melhorias</p>
        </div>
        <button 
          onClick={() => setShowForm(true)} 
          className="bg-slate-900 text-white px-6 py-3 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-blue-600 transition-all flex items-center gap-2 shadow-xl"
        >
          <Plus size={18} /> Novo Ticket
        </button>
      </header>

      {showForm && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[200] flex items-center justify-center p-4">
           <form onSubmit={handleAddRequest} className="bg-white rounded-[32px] w-full max-w-lg p-8 space-y-6 shadow-2xl border border-slate-100 animate-in zoom-in-95">
              <div className="flex justify-between items-center border-b pb-4">
                 <h3 className="text-sm font-black uppercase text-slate-900">Descreva sua Solicitação</h3>
                 <button type="button" onClick={() => setShowForm(false)} className="text-slate-300 hover:text-slate-900"><X size={20}/></button>
              </div>
              <textarea 
                required
                className="w-full bg-slate-50 border border-slate-200 p-5 rounded-2xl text-[11px] font-black uppercase outline-none focus:bg-white focus:border-slate-900 h-40 resize-none"
                placeholder="EXPLIQUE O QUE PRECISA (DÚVIDA, BUG OU SUGESTÃO)..."
                value={description}
                onChange={e => setDescription(e.target.value)}
              />
              <button 
                disabled={isLoading}
                type="submit"
                className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-emerald-600 transition-all flex items-center justify-center gap-2 shadow-lg"
              >
                {isLoading ? <Loader2 className="animate-spin" size={18}/> : 'ABRIR CHAMADO'}
              </button>
           </form>
        </div>
      )}

      <div className="grid grid-cols-1 gap-4">
        {state.supportRequests.length === 0 ? (
          <div className="bg-white p-20 rounded-[32px] border-2 border-dashed border-slate-200 text-center text-slate-400 font-black uppercase text-xs italic opacity-40">
            Nenhum ticket de suporte aberto no momento
          </div>
        ) : (
          state.supportRequests.map(req => (
            <div key={req.id} className="bg-white p-6 rounded-[32px] border border-slate-100 shadow-sm flex items-center justify-between gap-6 hover:border-slate-200 transition-all">
               <div className="flex items-center gap-5 flex-1">
                  <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${req.status === 'concluido' ? 'bg-emerald-50 text-emerald-600' : 'bg-amber-50 text-amber-600'}`}>
                     {req.status === 'concluido' ? <CheckCircle2 size={24}/> : <Clock size={24}/>}
                  </div>
                  <div>
                     <p className="text-[11px] font-black uppercase text-slate-800 leading-tight">{req.description}</p>
                     <p className="text-[8px] font-bold text-slate-400 uppercase tracking-widest mt-1">Aberto em: {new Date(req.createdAt).toLocaleString('pt-BR')}</p>
                  </div>
               </div>

               <div className="flex items-center gap-2">
                  <button 
                    onClick={() => toggleStatus(req)}
                    className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase transition-all shadow-sm ${req.status === 'concluido' ? 'bg-slate-100 text-slate-500' : 'bg-emerald-600 text-white hover:bg-emerald-700'}`}
                  >
                    {req.status === 'concluido' ? 'REABRIR' : 'CONCLUIR'}
                  </button>
                  <button 
                    onClick={() => handleDelete(req.id)}
                    className="p-2 text-slate-200 hover:text-rose-600 transition-colors"
                  >
                    <Trash2 size={18}/>
                  </button>
               </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

